import{_ as e,o as a,c as t,ag as n}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Certification vs Compliance","description":"","frontmatter":{},"headers":[],"relativePath":"en/standards/fundamentals/certification-vs-compliance.md","filePath":"en/standards/fundamentals/certification-vs-compliance.md"}'),o={name:"en/standards/fundamentals/certification-vs-compliance.md"};function r(l,i,s,c,d,p){return a(),t("div",null,[...i[0]||(i[0]=[n('<h1 id="certification-vs-compliance" tabindex="-1">Certification vs Compliance <a class="header-anchor" href="#certification-vs-compliance" aria-label="Permalink to &quot;Certification vs Compliance&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Certification and compliance are related but different concepts used to determine whether a product or system meets a standard.</p><p>Compliance means that a product is designed and built according to a standard.<br> Certification means that a recognized third party has verified that compliance through testing and evaluation.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Understanding the difference is critical to:</p><ul><li>Ensure equipment can be legally installed and operated</li><li>Pass inspections and approvals</li><li>Avoid project delays or rework</li><li>Select components that meet project requirements</li></ul><p>Both concepts are used to reduce risk, but they provide different levels of assurance.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><h3 id="compliance" tabindex="-1">Compliance <a class="header-anchor" href="#compliance" aria-label="Permalink to &quot;Compliance&quot;">​</a></h3><p>Compliance is a manufacturer’s declaration that a product meets a specific standard.</p><p>It is typically based on:</p><ul><li>Internal design practices</li><li>Engineering validation</li><li>Manufacturer testing</li></ul><p>Compliance does not always require external verification.</p><h3 id="certification" tabindex="-1">Certification <a class="header-anchor" href="#certification" aria-label="Permalink to &quot;Certification&quot;">​</a></h3><p>Certification involves an independent organization that:</p><ul><li>Tests the product against a standard</li><li>Verifies construction and performance</li><li>Audits manufacturing processes (in some cases)</li><li>Authorizes the use of a certification mark</li></ul><p>Examples include listing, labeling, or marking by recognized bodies.</p><p>Certification provides documented proof that the product meets the standard.</p><h2 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h2><h3 id="compliance-is-commonly-used-in" tabindex="-1">Compliance is commonly used in: <a class="header-anchor" href="#compliance-is-commonly-used-in" aria-label="Permalink to &quot;Compliance is commonly used in:&quot;">​</a></h3><ul><li>Internal engineering specifications</li><li>Non-regulated environments</li><li>Early design stages</li><li>Custom-built systems without mandatory certification</li></ul><h3 id="certification-is-typically-required-in" tabindex="-1">Certification is typically required in: <a class="header-anchor" href="#certification-is-typically-required-in" aria-label="Permalink to &quot;Certification is typically required in:&quot;">​</a></h3><ul><li>Control panels and industrial equipment</li><li>Electrical protection devices</li><li>Equipment subject to inspection or authority approval</li><li>Installations governed by local regulations</li></ul><h2 id="key-considerations" tabindex="-1">Key Considerations <a class="header-anchor" href="#key-considerations" aria-label="Permalink to &quot;Key Considerations&quot;">​</a></h2><ul><li>Certification is often required by authorities, not just recommended</li><li>A compliant product may still be rejected if not certified</li><li>Certification scope matters (component vs complete system)</li><li>Different regions require different certification bodies</li><li>Documentation and markings must match the standard used</li></ul><h2 id="practical-notes" tabindex="-1">Practical Notes <a class="header-anchor" href="#practical-notes" aria-label="Permalink to &quot;Practical Notes&quot;">​</a></h2><ul><li>Do not assume compliance is sufficient for installation approval</li><li>Verify certification requirements early in the project</li><li>Look for official certification marks on equipment</li><li>For custom assemblies (e.g., panels), certification may apply to the full system, not only components</li><li>Missing certification is a common cause of failed inspections</li></ul>',28)])])}const f=e(o,[["render",r]]);export{m as __pageData,f as default};
